class Solution {
    public ListNode mergeKLists(ListNode[] lists) {
        int n = lists.length;
        ListNode head = null, curr = null, next = null;
        for (int i = 0; i < n; i++) {
            ListNode temp = lists[i];
            while (temp != null) {
                if (curr == null || temp.val < curr.val) {
                    curr.next = temp;
                    curr = temp;
                } else {
                    next.next = temp;
                    next = temp;
                }
                temp = temp.next;
            }
        }
        head.next = next;
        return head;
    }
}
```

